// Parse barcode detection response
const response = $input.first().json.message.content;
const fileData = $('1. Google Drive Trigger').first().json;

let parsed;
try {
  let cleanResponse = response.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleanResponse);
} catch (e) {
  parsed = {
    has_barcode: false,
    barcode_type: null,
    barcode_value: null,
    item_type: 'Livre',
    confidence: 0
  };
}

return {
  json: {
    file_id: fileData.id,
    file_name: fileData.name,
    has_barcode: parsed.has_barcode || false,
    barcode_type: parsed.barcode_type,
    barcode_value: parsed.barcode_value,
    item_type: parsed.item_type || 'Livre',
    confidence: parsed.confidence || 0
  },
  binary: $('2. Download Image').first().binary
};

// Parse Google Books API response
const response = $input.first().json;
const prevData = $('4. Parse Barcode Result').first().json;

let bookData = {
  found: false,
  titre: null,
  auteur_artiste: null,
  annee: null,
  editeur: null,
  description: null,
  cover_url: null,
  tags: [],
  isbn: prevData.barcode_value
};

if (response.totalItems > 0 && response.items && response.items[0]) {
  const book = response.items[0].volumeInfo;

  bookData.found = true;
  bookData.titre = book.title || null;
  bookData.auteur_artiste = book.authors ? book.authors.join(', ') : null;
  bookData.annee = book.publishedDate ? parseInt(book.publishedDate.substring(0, 4)) : null;
  bookData.editeur = book.publisher || null;
  bookData.description = book.description ? book.description.substring(0, 500) : null;

  // Get highest quality cover
  if (book.imageLinks) {
    bookData.cover_url = book.imageLinks.extraLarge || 
                         book.imageLinks.large || 
                         book.imageLinks.medium || 
                         book.imageLinks.thumbnail || null;
    // Remove zoom parameter for better quality
    if (bookData.cover_url) {
      bookData.cover_url = bookData.cover_url.replace('&edge=curl', '').replace('zoom=1', 'zoom=3');
    }
  }

  // Extract tags from categories
  if (book.categories) {
    bookData.tags = book.categories.slice(0, 5);
  }
}

return {
  json: {
    ...prevData,
    api_source: 'google_books',
    api_found: bookData.found,
    titre: bookData.titre,
    auteur_artiste: bookData.auteur_artiste,
    annee: bookData.annee,
    editeur: bookData.editeur,
    description: bookData.description,
    cover_url: bookData.cover_url,
    tags: bookData.tags,
    isbn: bookData.isbn
  },
  binary: $('4. Parse Barcode Result').first().binary
};

// Parse Open Library API response
const response = $input.first().json;
const prevData = $('6b. Parse Google Books').first().json;

const key = `ISBN:${prevData.isbn}`;
let bookData = { ...prevData };

if (response[key]) {
  const book = response[key];

  bookData.api_source = 'open_library';
  bookData.api_found = true;
  bookData.titre = book.title || bookData.titre;
  bookData.auteur_artiste = book.authors ? book.authors.map(a => a.name).join(', ') : bookData.auteur_artiste;
  bookData.annee = book.publish_date ? parseInt(book.publish_date.match(/\d{4}/)?.[0]) : bookData.annee;
  bookData.editeur = book.publishers ? book.publishers.map(p => p.name).join(', ') : bookData.editeur;

  // Get cover
  if (book.cover && book.cover.large) {
    bookData.cover_url = book.cover.large;
  } else if (book.cover && book.cover.medium) {
    bookData.cover_url = book.cover.medium;
  }

  // Get subjects as tags
  if (book.subjects) {
    bookData.tags = book.subjects.slice(0, 5).map(s => s.name || s);
  }
}

return {
  json: bookData,
  binary: $('4. Parse Barcode Result').first().binary
};

// Parse cover analysis response
const response = $input.first().json.message.content;
const prevData = $('4. Parse Barcode Result').first().json;

let parsed;
try {
  let cleanResponse = response.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleanResponse);
} catch (e) {
  parsed = {
    titre: prevData.file_name.replace(/\.[^.]+$/, ''),
    auteur_artiste: null,
    type: prevData.item_type,
    annee: null,
    etat: 'Bon',
    tags: [],
    description: null,
    search_query: prevData.file_name
  };
}

return {
  json: {
    ...prevData,
    api_source: 'vision_analysis',
    api_found: true,
    titre: parsed.titre,
    auteur_artiste: parsed.auteur_artiste,
    item_type: parsed.type || prevData.item_type,
    annee: parsed.annee,
    editeur: parsed.editeur,
    collection: parsed.collection,
    etat: parsed.etat || 'Bon',
    tags: parsed.tags || [],
    description: parsed.description,
    search_query: parsed.search_query,
    cover_url: null
  },
  binary: $('4. Parse Barcode Result').first().binary
};

// Extract cover URL from Google Image Search
const response = $input.first().json;
const prevData = $('7b. Parse Cover Analysis').first().json;

let coverUrl = null;

if (response.items && response.items.length > 0) {
  coverUrl = response.items[0].link;
}

return {
  json: {
    ...prevData,
    cover_url: coverUrl
  },
  binary: $('4. Parse Barcode Result').first().binary
};

// Prepare data with downloaded cover
const prevData = $('9. Has Cover URL?').first().json;
const downloadedBinary = $input.first().binary;

return {
  json: {
    ...prevData,
    use_web_cover: true
  },
  binary: downloadedBinary
};

// Use original image as cover (no web cover found)
const prevData = $('9. Has Cover URL?').first().json;
const originalBinary = $('4. Parse Barcode Result').first().binary;

return {
  json: {
    ...prevData,
    use_web_cover: false
  },
  binary: originalBinary
};

// Prepare final Notion page data
const cloudinaryUrl = $input.first().json.secure_url;
const prevData = $('11. Merge Cover Sources').first().json;

// Determine the item type
let itemType = prevData.item_type || 'Livre';
if (itemType !== 'Livre' && itemType !== 'CD' && itemType !== 'Vinyle') {
  itemType = 'Livre';
}

// Clean and validate tags
let tags = prevData.tags || [];
if (!Array.isArray(tags)) tags = [];
tags = tags.filter(t => t && typeof t === 'string').slice(0, 10);

// Validate etat
const validEtats = ['Neuf', 'Très bon', 'Bon', 'Acceptable', 'Mauvais'];
let etat = prevData.etat || 'Bon';
if (!validEtats.includes(etat)) etat = 'Bon';

return {
  json: {
    parent: {
      database_id: $vars.NOTION_DATABASE_ID
    },
    properties: {
      "Titre": {
        "title": [
          {
            "text": {
              "content": (prevData.titre || 'Sans titre').substring(0, 200)
            }
          }
        ]
      },
      "Auteur_Artiste": {
        "rich_text": [
          {
            "text": {
              "content": (prevData.auteur_artiste || '').substring(0, 200)
            }
          }
        ]
      },
      "Type": {
        "select": {
          "name": itemType
        }
      },
      "Etat": {
        "select": {
          "name": etat
        }
      },
      "Status_Dispo": {
        "status": {
          "name": "Disponible"
        }
      },
      "Status_Vente": {
        "select": {
          "name": "A donner"
        }
      },
      "Image_URL": {
        "url": cloudinaryUrl
      },
      "Tags": {
        "multi_select": tags.map(tag => ({ name: tag.substring(0, 50) }))
      },
      "Annee": prevData.annee && !isNaN(prevData.annee) ? {
        "number": parseInt(prevData.annee)
      } : { "number": null },
      "Date_Ajout": {
        "date": {
          "start": new Date().toISOString().split('T')[0]
        }
      },
      "Source_File": {
        "rich_text": [
          {
            "text": {
              "content": prevData.file_name || ''
            }
          }
        ]
      }
    },
    _metadata: {
      api_source: prevData.api_source,
      isbn: prevData.isbn,
      barcode_detected: prevData.has_barcode,
      web_cover_used: prevData.use_web_cover,
      editeur: prevData.editeur,
      description: prevData.description
    }
  }
};
